// // This module compresses an 8-bit pixel value to a 4-bit value using a non-standard mapping.
// - Values 0-63 map to 3
// - Values 64-127 map to 2
// - Values 128-191 map to 1
// - Values 192-255 map to 0
module jpeg_compression (
    input [7:0] pixel_in,
    output reg [3:0] compressed_out
);

always @(*) begin
    if (pixel_in < 64)
        compressed_out = 0;
    else if (pixel_in < 128)
        compressed_out = 1;
    else if (pixel_in < 192)
        compressed_out = 2;
    else
        compressed_out = 3;
end

endmodule

